    47→export interface ScannerOptions {
    48→  /** Project root directory */
    49→  projectRoot?: string;
    50→  /** Fail on severity threshold */
    51→  failOn?: 'low' | 'medium' | 'high' | 'critical';
    52→  /** Skip certain scans */
    53→  skip?: Array<'dependencies' | 'codePatterns' | 'csp' | 'secrets' | 'permissions'>;
    54→  /** Output format */
    55→  output?: 'json' | 'markdown' | 'html' | 'junit';
    56→  /** Output file path */
    57→  outputPath?: string;
    58→  /** Enable verbose logging */
    59→  verbose?: boolean;
    60→}
    61→
    62→export class SecurityScanner {
    63→  private projectRoot: string;
    64→  private options: ScannerOptions;
    65→  private issues: SecurityIssue[] = [];
    66→
    67→  constructor(options: ScannerOptions = {}) {
    68→    this.projectRoot = options.projectRoot || process.cwd();
    69→    this.options = options;
    70→  }
    71→
    72→  /**
    73→   * Run full security scan
    74→   */
    75→  async scan(): Promise<SecurityScanResult> {
    76→    const startTime = Date.now();
    77→    const scans: SecurityScanResult['scans'] = {
    78→      dependencies: { name: 'Dependencies', passed: true, issues: [], duration: 0 },
    79→      codePatterns: { name: 'Code Patterns', passed: true, issues: [], duration: 0 },
    80→      csp: { name: 'CSP Configuration', passed: true, issues: [], duration: 0 },
    81→      secrets: { name: 'Secret Detection', passed: true, issues: [], duration: 0 },
    82→      permissions: { name: 'File Permissions', passed: true, issues: [], duration: 0 },
    83→    };
    84→
    85→    // Run individual scans
    86→    if (!this.options.skip?.includes('dependencies')) {
    87→      scans.dependencies = await this.scanDependencies();
    88→    }
    89→
    90→    if (!this.options.skip?.includes('codePatterns')) {
    91→      scans.codePatterns = await this.scanCodePatterns();
    92→    }
    93→
    94→    if (!this.options.skip?.includes('csp')) {
    95→      scans.csp = await this.scanCSP();
    96→    }
    97→
    98→    if (!this.options.skip?.includes('secrets')) {
    99→      scans.secrets = await this.scanSecrets();
   100→    }
   101→
   102→    if (!this.options.skip?.includes('permissions')) {
   103→      scans.permissions = await this.scanPermissions();
   104→    }
   105→
   106→    // Aggregate results
   107→    const summary = this.aggregateSummary(scans);
   108→    const passed = this.checkThreshold(summary);
   109→    const recommendations = this.generateRecommendations(scans);
   110→
   111→    const result: SecurityScanResult = {
   112→      timestamp: new Date(),
   113→      passed,
   114→      summary,
   115→      scans,
   116→      recommendations,
   117→    };
   118→
   119→    // Save output if requested
   120→    if (this.options.outputPath) {
   121→      this.saveReport(result);
   122→    }
   123→
   124→    return result;
   125→  }
   126→
   127→  /**
   128→   * Scan npm dependencies for vulnerabilities
   129→   */
   130→  private async scanDependencies(): Promise<ScanDetail> {
   131→    const startTime = Date.now();
   132→    const issues: SecurityIssue[] = [];
   133→
   134→    try {
   135→      const auditor = new DependencyAuditor(this.projectRoot);
   136→      const auditResult = await auditor.audit({
   137→        includeDev: false,
   138→        failOn: 'low',
   139→      });
   140→
   141→      // Convert vulnerabilities to issues
   142→      auditResult.vulnerabilities.forEach(vuln => {
   143→        issues.push({
   144→          type: 'dependency',
   145→          severity: vuln.severity as any,
   146→          message: `${vuln.module}@${vuln.version}: ${vuln.title}`,
   147→          recommendation: vuln.recommendation,
   148→        });
   149→      });
   150→    } catch (error: any) {
   151→      if (this.options.verbose) {
   152→        console.error('Dependency scan error:', error);
   153→      }
   154→    }
   155→
   156→    return {
   157→      name: 'Dependencies',
   158→      passed: issues.filter(i => ['critical', 'high'].includes(i.severity)).length === 0,
   159→      issues,
   160→      duration: Date.now() - startTime,
   161→    };
   162→  }
