   164→  /**
   165→   * Scan code for dangerous patterns
   166→   */
   167→  private async scanCodePatterns(): Promise<ScanDetail> {
   168→    const startTime = Date.now();
   169→    const issues: SecurityIssue[] = [];
   170→
   171→    const patterns = [
   172→      {
   173→        pattern: /eval\s*\(/g,
   174→        severity: 'high' as const,
   175→        message: 'Use of eval() is dangerous and can lead to code injection',
   176→        recommendation: 'Use safer alternatives like JSON.parse() or Function constructor',
   177→      },
   178→      {
   179→        pattern: /innerHTML\s*=/g,
   180→        severity: 'medium' as const,
   181→        message: 'Direct innerHTML assignment can lead to XSS',
   182→        recommendation: 'Use textContent or sanitize HTML before assignment',
   183→      },
   184→      {
   185→        pattern: /document\.write/g,
   186→        severity: 'medium' as const,
   187→        message: 'document.write() can be dangerous',
   188→        recommendation: 'Use DOM manipulation methods instead',
   189→      },
   190→      {
   191→        pattern: /new\s+Function\s*\(/g,
   192→        severity: 'medium' as const,
   193→        message: 'Dynamic function creation can be risky',
   194→        recommendation: 'Use predefined functions or safer alternatives',
   195→      },
   196→      {
   197→        pattern: /\$\(.*\)\.html\s*\(/g,
   198→        severity: 'medium' as const,
   199→        message: 'jQuery html() can lead to XSS',
   200→        recommendation: 'Sanitize content before using html()',
   201→      },
   202→      {
   203→        pattern: /crypto\.pseudoRandomBytes/g,
   204→        severity: 'high' as const,
   205→        message: 'pseudoRandomBytes is not cryptographically secure',
   206→        recommendation: 'Use crypto.randomBytes() instead',
   207→      },
   208→      {
   209→        pattern: /Math\.random\(\)/g,
   210→        severity: 'low' as const,
   211→        message: 'Math.random() is not cryptographically secure',
   212→        recommendation: 'Use crypto.getRandomValues() for security-sensitive randomness',
   213→      },
   214→    ];
   215→
   216→    // Scan TypeScript/JavaScript files
   217→    const files = this.findFiles(['**/*.ts', '**/*.js'], ['node_modules', 'dist', 'build']);
   218→    
   219→    for (const file of files) {
   220→      const content = readFileSync(file, 'utf8');
   221→      const lines = content.split('\n');
   222→
   223→      patterns.forEach(({ pattern, severity, message, recommendation }) => {
   224→        lines.forEach((line, index) => {
   225→          if (pattern.test(line)) {
   226→            issues.push({
   227→              type: 'pattern',
   228→              severity,
   229→              file,
   230→              line: index + 1,
   231→              message,
   232→              recommendation,
   233→            });
   234→          }
   235→        });
   236→      });
   237→    }
   238→
   239→    return {
   240→      name: 'Code Patterns',
   241→      passed: issues.filter(i => ['critical', 'high'].includes(i.severity)).length === 0,
   242→      issues,
   243→      duration: Date.now() - startTime,
   244→    };
   245→  }
