   298→  /**
   299→   * Scan for exposed secrets
   300→   */
   301→  private async scanSecrets(): Promise<ScanDetail> {
   302→    const startTime = Date.now();
   303→    const issues: SecurityIssue[] = [];
   304→
   305→    const secretPatterns = [
   306→      {
   307→        pattern: /(?:api[_-]?key|apikey)\s*[:=]\s*['"]([^'"]+)['"]/gi,
   308→        type: 'API Key',
   309→      },
   310→      {
   311→        pattern: /(?:secret|password|passwd|pwd)\s*[:=]\s*['"]([^'"]+)['"]/gi,
   312→        type: 'Password/Secret',
   313→      },
   314→      {
   315→        pattern: /(?:aws[_-]?access[_-]?key[_-]?id)\s*[:=]\s*['"]([^'"]+)['"]/gi,
   316→        type: 'AWS Access Key',
   317→      },
   318→      {
   319→        pattern: /(?:aws[_-]?secret[_-]?access[_-]?key)\s*[:=]\s*['"]([^'"]+)['"]/gi,
   320→        type: 'AWS Secret Key',
   321→      },
   322→      {
   323→        pattern: /(?:private[_-]?key)\s*[:=]\s*['"]([^'"]+)['"]/gi,
   324→        type: 'Private Key',
   325→      },
   326→      {
   327→        pattern: /mongodb:\/\/[^:]+:[^@]+@/gi,
   328→        type: 'MongoDB Connection String',
   329→      },
   330→      {
   331→        pattern: /postgres:\/\/[^:]+:[^@]+@/gi,
   332→        type: 'PostgreSQL Connection String',
   333→      },
   334→    ];
   335→
   336→    const files = this.findFiles(['**/*'], ['node_modules', 'dist', 'build', '*.lock']);
   337→
   338→    for (const file of files) {
   339→      // Skip binary files
   340→      if (this.isBinaryFile(file)) continue;
   341→
   342→      try {
   343→        const content = readFileSync(file, 'utf8');
   344→        
   345→        secretPatterns.forEach(({ pattern, type }) => {
   346→          const matches = content.match(pattern);
   347→          if (matches) {
   348→            issues.push({
   349→              type: 'secret',
   350→              severity: 'critical',
   351→              file,
   352→              message: `Potential ${type} exposed`,
   353→              recommendation: 'Move secrets to environment variables or secure key management',
   354→            });
   355→          }
   356→        });
   357→      } catch (error) {
   358→        // Skip files that can't be read as text
   359→      }
   360→    }
   361→
   362→    return {
   363→      name: 'Secret Detection',
   364→      passed: issues.length === 0,
   365→      issues,
   366→      duration: Date.now() - startTime,
   367→    };
   368→  }
