   432→  private isBinaryFile(filePath: string): boolean {
   433→    const binaryExtensions = ['.png', '.jpg', '.jpeg', '.gif', '.ico', '.pdf', '.zip', '.tar', '.gz'];
   434→    return binaryExtensions.some(ext => filePath.endsWith(ext));
