   437→  /**
   438→   * Aggregate scan summary
   439→   */
   440→  private aggregateSummary(scans: SecurityScanResult['scans']): SecurityScanResult['summary'] {
   441→    const summary = {
   442→      critical: 0,
   443→      high: 0,
   444→      medium: 0,
   445→      low: 0,
   446→      total: 0,
   447→    };
   448→
   449→    Object.values(scans).forEach(scan => {
   450→      scan.issues.forEach(issue => {
   451→        summary[issue.severity]++;
   452→        summary.total++;
   453→      });
   454→    });
   455→
   456→    return summary;
