   459→  /**
   460→   * Check if scan passes threshold
   461→   */
   462→  private checkThreshold(summary: SecurityScanResult['summary']): boolean {
   463→    if (!this.options.failOn) return true;
   464→
   465→    const thresholds = {
   466→      critical: ['critical'],
   467→      high: ['critical', 'high'],
   468→      medium: ['critical', 'high', 'medium'],
   469→      low: ['critical', 'high', 'medium', 'low'],
   470→    };
   471→
   472→    const failSeverities = thresholds[this.options.failOn];
   473→    
   474→    return failSeverities.every(severity => 
   475→      summary[severity as keyof typeof summary] === 0
   476→    );
   477→  }
