   479→  /**
   480→   * Generate security recommendations
   481→   */
   482→  private generateRecommendations(scans: SecurityScanResult['scans']): string[] {
   483→    const recommendations: string[] = [];
   484→
   485→    // Check each scan type
   486→    Object.entries(scans).forEach(([type, scan]) => {
   487→      if (scan.issues.length > 0) {
   488→        const criticalCount = scan.issues.filter(i => i.severity === 'critical').length;
   489→        const highCount = scan.issues.filter(i => i.severity === 'high').length;
   490→
   491→        if (criticalCount > 0) {
   492→          recommendations.push(
   493→            `🚨 Address ${criticalCount} critical ${type} issues immediately`
   494→          );
   495→        }
   496→        if (highCount > 0) {
   497→          recommendations.push(
   498→            `⚠️  Fix ${highCount} high-severity ${type} issues before deployment`
   499→          );
   500→        }
   501→      }
   502→    });
   503→
   504→    // General recommendations
   505→    if (recommendations.length === 0) {
   506→      recommendations.push('✅ No critical security issues found');
   507→      recommendations.push('📋 Continue regular security scanning');
   508→      recommendations.push('🔄 Keep dependencies up to date');
   509→    }
   510→
   511→    return recommendations;
   512→  }
