/**
 * Security Scanner for CI/CD pipeline integration
 */

import { execSync } from 'child_process';
import { readFileSync, writeFileSync, existsSync } from 'fs';
import { join, resolve } from 'path';
import { DependencyAuditor } from './DependencyAuditor';
import { ContentSecurityPolicy } from './ContentSecurityPolicy';

export interface SecurityScanResult {
  timestamp: Date;
  passed: boolean;
  summary: {
    critical: number;
    high: number;
    medium: number;
    low: number;
    total: number;
  };
  scans: {
    dependencies: ScanDetail;
    codePatterns: ScanDetail;
    csp: ScanDetail;
    secrets: ScanDetail;
    permissions: ScanDetail;
  };
  recommendations: string[];
}

export interface ScanDetail {
  name: string;
  passed: boolean;
  issues: SecurityIssue[];
  duration: number;
}

export interface SecurityIssue {
  type: string;
  severity: 'critical' | 'high' | 'medium' | 'low';
  file?: string;
  line?: number;
  message: string;
  recommendation?: string;
}

export interface ScannerOptions {
  /** Project root directory */
  projectRoot?: string;
  /** Fail on severity threshold */
  failOn?: 'low' | 'medium' | 'high' | 'critical';
  /** Skip certain scans */
  skip?: Array<'dependencies' | 'codePatterns' | 'csp' | 'secrets' | 'permissions'>;
  /** Output format */
  output?: 'json' | 'markdown' | 'html' | 'junit';
  /** Output file path */
  outputPath?: string;
  /** Enable verbose logging */
  verbose?: boolean;
}

export class SecurityScanner {
  private projectRoot: string;
  private options: ScannerOptions;
  private issues: SecurityIssue[] = [];

  constructor(options: ScannerOptions = {}) {
    this.projectRoot = options.projectRoot || process.cwd();
    this.options = options;
  }

  /**
   * Run full security scan
   */
  async scan(): Promise<SecurityScanResult> {
    const startTime = Date.now();
    const scans: SecurityScanResult['scans'] = {
      dependencies: { name: 'Dependencies', passed: true, issues: [], duration: 0 },
      codePatterns: { name: 'Code Patterns', passed: true, issues: [], duration: 0 },
      csp: { name: 'CSP Configuration', passed: true, issues: [], duration: 0 },
      secrets: { name: 'Secret Detection', passed: true, issues: [], duration: 0 },
      permissions: { name: 'File Permissions', passed: true, issues: [], duration: 0 },
    };

    // Run individual scans
    if (!this.options.skip?.includes('dependencies')) {
      scans.dependencies = await this.scanDependencies();
    }

    if (!this.options.skip?.includes('codePatterns')) {
      scans.codePatterns = await this.scanCodePatterns();
    }

    if (!this.options.skip?.includes('csp')) {
      scans.csp = await this.scanCSP();
    }

    if (!this.options.skip?.includes('secrets')) {
      scans.secrets = await this.scanSecrets();
    }

    if (!this.options.skip?.includes('permissions')) {
      scans.permissions = await this.scanPermissions();
    }

    // Aggregate results
    const summary = this.aggregateSummary(scans);
    const passed = this.checkThreshold(summary);
    const recommendations = this.generateRecommendations(scans);

    const result: SecurityScanResult = {
      timestamp: new Date(),
      passed,
      summary,
      scans,
      recommendations,
    };

    // Save output if requested
    if (this.options.outputPath) {
      this.saveReport(result);
    }

    return result;
  }

  /**
   * Scan npm dependencies for vulnerabilities
   */
  private async scanDependencies(): Promise<ScanDetail> {
    const startTime = Date.now();
    const issues: SecurityIssue[] = [];

    try {
      const auditor = new DependencyAuditor(this.projectRoot);
      const auditResult = await auditor.audit({
        includeDev: false,
        failOn: 'low',
      });

      // Convert vulnerabilities to issues
      auditResult.vulnerabilities.forEach(vuln => {
        issues.push({
          type: 'dependency',
          severity: vuln.severity as any,
          message: `${vuln.module}@${vuln.version}: ${vuln.title}`,
          recommendation: vuln.recommendation,
        });
      });
    } catch (error: any) {
      if (this.options.verbose) {
        console.error('Dependency scan error:', error);
      }
    }

    return {
      name: 'Dependencies',
      passed: issues.filter(i => ['critical', 'high'].includes(i.severity)).length === 0,
      issues,
      duration: Date.now() - startTime,
    };
  }

  /**
   * Scan code for dangerous patterns
   */
  private async scanCodePatterns(): Promise<ScanDetail> {
    const startTime = Date.now();
    const issues: SecurityIssue[] = [];

    const patterns = [
      {
        pattern: /eval\s*\(/g,
        severity: 'high' as const,
        message: 'Use of eval() is dangerous and can lead to code injection',
        recommendation: 'Use safer alternatives like JSON.parse() or Function constructor',
      },
      {
        pattern: /innerHTML\s*=/g,
        severity: 'medium' as const,
        message: 'Direct innerHTML assignment can lead to XSS',
        recommendation: 'Use textContent or sanitize HTML before assignment',
      },
      {
        pattern: /document\.write/g,
        severity: 'medium' as const,
        message: 'document.write() can be dangerous',
        recommendation: 'Use DOM manipulation methods instead',
      },
      {
        pattern: /new\s+Function\s*\(/g,
        severity: 'medium' as const,
        message: 'Dynamic function creation can be risky',
        recommendation: 'Use predefined functions or safer alternatives',
      },
      {
        pattern: /\$\(.*\)\.html\s*\(/g,
        severity: 'medium' as const,
        message: 'jQuery html() can lead to XSS',
        recommendation: 'Sanitize content before using html()',
      },
      {
        pattern: /crypto\.pseudoRandomBytes/g,
        severity: 'high' as const,
        message: 'pseudoRandomBytes is not cryptographically secure',
        recommendation: 'Use crypto.randomBytes() instead',
      },
      {
        pattern: /Math\.random\(\)/g,
        severity: 'low' as const,
        message: 'Math.random() is not cryptographically secure',
        recommendation: 'Use crypto.getRandomValues() for security-sensitive randomness',
      },
    ];

    // Scan TypeScript/JavaScript files
    const files = this.findFiles(['**/*.ts', '**/*.js'], ['node_modules', 'dist', 'build']);

    for (const file of files) {
      const content = readFileSync(file, 'utf8');
      const lines = content.split('\n');

      patterns.forEach(({ pattern, severity, message, recommendation }) => {
        lines.forEach((line, index) => {
          if (pattern.test(line)) {
            issues.push({
              type: 'pattern',
              severity,
              file,
              line: index + 1,
              message,
              recommendation,
            });
          }
        });
      });
    }

    return {
      name: 'Code Patterns',
      passed: issues.filter(i => ['critical', 'high'].includes(i.severity)).length === 0,
      issues,
      duration: Date.now() - startTime,
    };
  }

  /**
   * Scan CSP configuration
   */
  private async scanCSP(): Promise<ScanDetail> {
    const startTime = Date.now();
    const issues: SecurityIssue[] = [];

    try {
      const csp = ContentSecurityPolicy.getInstance();
      const warnings = csp.validate();

      warnings.forEach(warning => {
        issues.push({
          type: 'csp',
          severity: warning.includes('unsafe-eval') ? 'high' : 'medium',
          message: warning,
          recommendation: 'Review and tighten CSP directives',
        });
      });

      // Check for missing security headers
      const requiredHeaders = [
        'Strict-Transport-Security',
        'X-Content-Type-Options',
        'X-Frame-Options',
        'X-XSS-Protection',
      ];

      // This is a simplified check - in production, would check actual server config
      if (issues.length === 0) {
        issues.push({
          type: 'csp',
          severity: 'low',
          message: 'Ensure all security headers are configured on the server',
          recommendation: `Configure headers: ${requiredHeaders.join(', ')}`,
        });
      }
    } catch (error: any) {
      if (this.options.verbose) {
        console.error('CSP scan error:', error);
      }
    }

    return {
      name: 'CSP Configuration',
      passed: issues.filter(i => ['critical', 'high'].includes(i.severity)).length === 0,
      issues,
      duration: Date.now() - startTime,
    };
  }

  /**
   * Scan for exposed secrets
   */
  private async scanSecrets(): Promise<ScanDetail> {
    const startTime = Date.now();
    const issues: SecurityIssue[] = [];

    const secretPatterns = [
      {
        pattern: /(?:api[_-]?key|apikey)\s*[:=]\s*['"]([^'"]+)['"]/gi,
        type: 'API Key',
      },
      {
        pattern: /(?:secret|password|passwd|pwd)\s*[:=]\s*['"]([^'"]+)['"]/gi,
        type: 'Password/Secret',
      },
      {
        pattern: /(?:aws[_-]?access[_-]?key[_-]?id)\s*[:=]\s*['"]([^'"]+)['"]/gi,
        type: 'AWS Access Key',
      },
      {
        pattern: /(?:aws[_-]?secret[_-]?access[_-]?key)\s*[:=]\s*['"]([^'"]+)['"]/gi,
        type: 'AWS Secret Key',
      },
      {
        pattern: /(?:private[_-]?key)\s*[:=]\s*['"]([^'"]+)['"]/gi,
        type: 'Private Key',
      },
      {
        pattern: /mongodb:\/\/[^:]+:[^@]+@/gi,
        type: 'MongoDB Connection String',
      },
      {
        pattern: /postgres:\/\/[^:]+:[^@]+@/gi,
        type: 'PostgreSQL Connection String',
      },
    ];

    const files = this.findFiles(['**/*'], ['node_modules', 'dist', 'build', '*.lock']);

    for (const file of files) {
      // Skip binary files
      if (this.isBinaryFile(file)) continue;

      try {
        const content = readFileSync(file, 'utf8');

        secretPatterns.forEach(({ pattern, type }) => {
          const matches = content.match(pattern);
          if (matches) {
            issues.push({
              type: 'secret',
              severity: 'critical',
              file,
              message: `Potential ${type} exposed`,
              recommendation: 'Move secrets to environment variables or secure key management',
            });
          }
        });
      } catch (error) {
        // Skip files that can't be read as text
      }
    }

    return {
      name: 'Secret Detection',
      passed: issues.length === 0,
      issues,
      duration: Date.now() - startTime,
    };
  }

  /**
   * Scan file permissions
   */
  private async scanPermissions(): Promise<ScanDetail> {
    const startTime = Date.now();
    const issues: SecurityIssue[] = [];

    try {
      // Check for world-writable files
      const output = execSync(
        `find ${this.projectRoot} -type f -perm -002 -not -path "*/node_modules/*" -not -path "*/.git/*" 2>/dev/null || true`,
        { encoding: 'utf8' }
      );

      const files = output.split('\n').filter(f => f.trim());
      files.forEach(file => {
        issues.push({
          type: 'permission',
          severity: 'medium',
          file,
          message: 'File is world-writable',
          recommendation: 'Remove write permissions for others: chmod o-w',
        });
      });
    } catch (error) {
      // Permission scan might fail on some systems
      if (this.options.verbose) {
        console.warn('Permission scan skipped:', error);
      }
    }

    return {
      name: 'File Permissions',
      passed: issues.length === 0,
      issues,
      duration: Date.now() - startTime,
    };
  }

  /**
   * Find files matching patterns
   */
  private findFiles(include: string[], exclude: string[]): string[] {
    // Simplified file finder - in production, use glob library
    const files: string[] = [];

    try {
      const findCmd = `find ${this.projectRoot} -type f ${exclude.map(e => `-not -path "*/${e}/*"`).join(' ')}`;
      const output = execSync(findCmd, { encoding: 'utf8' });
      files.push(...output.split('\n').filter(f => f.trim()));
    } catch (error) {
      if (this.options.verbose) {
        console.error('File search error:', error);
      }
    }

    return files;
  }

  /**
   * Check if file is binary
   */
  private isBinaryFile(filePath: string): boolean {
    const binaryExtensions = ['.png', '.jpg', '.jpeg', '.gif', '.ico', '.pdf', '.zip', '.tar', '.gz'];
    return binaryExtensions.some(ext => filePath.endsWith(ext));
  }

  /**
   * Aggregate scan summary
   */
  private aggregateSummary(scans: SecurityScanResult['scans']): SecurityScanResult['summary'] {
    const summary = {
      critical: 0,
      high: 0,
      medium: 0,
      low: 0,
      total: 0,
    };

    Object.values(scans).forEach(scan => {
      scan.issues.forEach(issue => {
        summary[issue.severity]++;
        summary.total++;
      });
    });

    return summary;
  }

  /**
   * Check if scan passes threshold
   */
  private checkThreshold(summary: SecurityScanResult['summary']): boolean {
    if (!this.options.failOn) return true;

    const thresholds = {
      critical: ['critical'],
      high: ['critical', 'high'],
      medium: ['critical', 'high', 'medium'],
      low: ['critical', 'high', 'medium', 'low'],
    };

    const failSeverities = thresholds[this.options.failOn];

    return failSeverities.every(severity => 
      summary[severity as keyof typeof summary] === 0
    );
  }

  /**
   * Generate security recommendations
   */
  private generateRecommendations(scans: SecurityScanResult['scans']): string[] {
    const recommendations: string[] = [];

    // Check each scan type
    Object.entries(scans).forEach(([type, scan]) => {
      if (scan.issues.length > 0) {
        const criticalCount = scan.issues.filter(i => i.severity === 'critical').length;
        const highCount = scan.issues.filter(i => i.severity === 'high').length;

        if (criticalCount > 0) {
          recommendations.push(
            `🚨 Address ${criticalCount} critical ${type} issues immediately`
          );
        }
        if (highCount > 0) {
          recommendations.push(
            `⚠️  Fix ${highCount} high-severity ${type} issues before deployment`
          );
        }
      }
    });

    // General recommendations
    if (recommendations.length === 0) {
      recommendations.push('✅ No critical security issues found');
      recommendations.push('📋 Continue regular security scanning');
      recommendations.push('🔄 Keep dependencies up to date');
    }

    return recommendations;
  }

  /**
   * Save scan report
   */
  private saveReport(result: SecurityScanResult): void {
    if (!this.options.outputPath) return;

    let content: string;

    switch (this.options.output) {
      case 'json':
        content = JSON.stringify(result, null, 2);
        break;
      case 'markdown':
        content = this.generateMarkdownReport(result);
        break;
      case 'html':
        content = this.generateHTMLReport(result);
        break;
      case 'junit':
        content = this.generateJUnitReport(result);
        break;
      default:
        content = JSON.stringify(result, null, 2);
    }

    writeFileSync(this.options.outputPath, content);
  }

  /**
   * Generate markdown report
   */
  private generateMarkdownReport(result: SecurityScanResult): string {
    let report = `# Security Scan Report\n\n`;
    report += `**Date:** ${result.timestamp.toISOString()}\n`;
    report += `**Status:** ${result.passed ? '✅ PASSED' : '❌ FAILED'}\n\n`;

    report += `## Summary\n\n`;
    report += `| Severity | Count |\n`;
    report += `|----------|-------|\n`;
    report += `| Critical | ${result.summary.critical} |\n`;
    report += `| High | ${result.summary.high} |\n`;
    report += `| Medium | ${result.summary.medium} |\n`;
    report += `| Low | ${result.summary.low} |\n`;
    report += `| **Total** | **${result.summary.total}** |\n\n`;

    report += `## Scan Results\n\n`;

    Object.entries(result.scans).forEach(([key, scan]) => {
      report += `### ${scan.name}\n\n`;
      report += `- **Status:** ${scan.passed ? 'PASSED' : 'FAILED'}\n`;
      report += `- **Duration:** ${scan.duration}ms\n`;
      report += `- **Issues:** ${scan.issues.length}\n\n`;

      if (scan.issues.length > 0) {
        scan.issues.forEach(issue => {
          report += `#### ${issue.severity.toUpperCase()}: ${issue.message}\n`;
          if (issue.file) {
            report += `- **File:** ${issue.file}`;
            if (issue.line) report += `:${issue.line}`;
            report += `\n`;
          }
          if (issue.recommendation) {
            report += `- **Recommendation:** ${issue.recommendation}\n`;
          }
          report += `\n`;
        });
      }
    });

    report += `## Recommendations\n\n`;
    result.recommendations.forEach(rec => {
      report += `- ${rec}\n`;
    });

    return report;
  }

  /**
   * Generate HTML report
   */
  private generateHTMLReport(result: SecurityScanResult): string {
    const severityColors = {
      critical: '#d32f2f',
      high: '#f44336',
      medium: '#ff9800',
      low: '#ffc107',
    };

    return `
<!DOCTYPE html>
<html>
<head>
  <title>Security Scan Report</title>
  <style>
    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      line-height: 1.6;
      color: #333;
      max-width: 1200px;
      margin: 0 auto;
      padding: 20px;
    }
    .header {
      background: ${result.passed ? '#4caf50' : '#f44336'};
      color: white;
      padding: 20px;
      border-radius: 8px;
      margin-bottom: 20px;
    }
    .summary {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
      gap: 15px;
      margin-bottom: 30px;
    }
    .metric {
      background: #f5f5f5;
      padding: 15px;
      border-radius: 4px;
      text-align: center;
    }
    .metric-value {
      font-size: 36px;
      font-weight: bold;
    }
    .scan-section {
      background: white;
      border: 1px solid #ddd;
      padding: 20px;
      margin-bottom: 20px;
      border-radius: 4px;
    }
    .issue {
      background: #f9f9f9;
      padding: 10px;
      margin: 10px 0;
      border-left: 4px solid #ddd;
    }
    .critical { border-left-color: ${severityColors.critical}; }
    .high { border-left-color: ${severityColors.high}; }
    .medium { border-left-color: ${severityColors.medium}; }
    .low { border-left-color: ${severityColors.low}; }
    .severity-badge {
      display: inline-block;
      padding: 2px 8px;
      border-radius: 3px;
      color: white;
      font-weight: bold;
      text-transform: uppercase;
      font-size: 12px;
    }
  </style>
</head>
<body>
  <div class="header">
    <h1>Security Scan Report</h1>
    <p>Status: ${result.passed ? '✅ PASSED' : '❌ FAILED'}</p>
    <p>Date: ${result.timestamp.toLocaleString()}</p>
  </div>

  <div class="summary">
    <div class="metric">
      <div class="metric-value" style="color: ${severityColors.critical}">${result.summary.critical}</div>
      <div>Critical</div>
    </div>
    <div class="metric">
      <div class="metric-value" style="color: ${severityColors.high}">${result.summary.high}</div>
      <div>High</div>
    </div>
    <div class="metric">
      <div class="metric-value" style="color: ${severityColors.medium}">${result.summary.medium}</div>
      <div>Medium</div>
    </div>
    <div class="metric">
      <div class="metric-value" style="color: ${severityColors.low}">${result.summary.low}</div>
      <div>Low</div>
    </div>
  </div>

  <h2>Scan Results</h2>
  ${Object.entries(result.scans).map(([key, scan]) => `
    <div class="scan-section">
      <h3>${scan.name}</h3>
      <p>Status: ${scan.passed ? '✅ Passed' : '❌ Failed'} | Duration: ${scan.duration}ms | Issues: ${scan.issues.length}</p>
      ${scan.issues.map(issue => `
        <div class="issue ${issue.severity}">
          <span class="severity-badge" style="background: ${severityColors[issue.severity]}">${issue.severity}</span>
          <strong>${issue.message}</strong>
          ${issue.file ? `<br>File: <code>${issue.file}${issue.line ? `:${issue.line}` : ''}</code>` : ''}
          ${issue.recommendation ? `<br>Recommendation: ${issue.recommendation}` : ''}
        </div>
      `).join('')}
    </div>
  `).join('')}

  <h2>Recommendations</h2>
  <ul>
    ${result.recommendations.map(rec => `<li>${rec}</li>`).join('')}
  </ul>
</body>
</html>
    `;
  }

  /**
   * Generate JUnit XML report
   */
  private generateJUnitReport(result: SecurityScanResult): string {
    const testcases = Object.entries(result.scans).map(([key, scan]) => {
      const failures = scan.issues
        .filter(i => ['critical', 'high'].includes(i.severity))
        .map(i => `<failure message="${i.message}" type="${i.severity}">${i.recommendation || ''}</failure>`)
        .join('\n');

      return `
    <testcase name="${scan.name}" time="${scan.duration / 1000}">
      ${failures}
    </testcase>`;
    }).join('\n');

    return `<?xml version="1.0" encoding="UTF-8"?>
<testsuites name="Security Scan" tests="${Object.keys(result.scans).length}" failures="${result.summary.critical + result.summary.high}" time="${Object.values(result.scans).reduce((sum, s) => sum + s.duration, 0) / 1000}">
  <testsuite name="Security" tests="${Object.keys(result.scans).length}" failures="${result.summary.critical + result.summary.high}">
${testcases}
  </testsuite>
</testsuites>`;
  }
}

