     1→/**
     2→ * Dependency Auditor for security vulnerability scanning
     3→ */
     4→
     5→import { execSync } from 'child_process';
     6→import { readFileSync, writeFileSync, existsSync } from 'fs';
     7→import { resolve, dirname } from 'path';
     8→
     9→export interface Vulnerability {
    10→  id: string;
    11→  title: string;
    12→  severity: 'low' | 'moderate' | 'high' | 'critical';
    13→  module: string;
    14→  version: string;
    15→  path: string;
    16→  recommendation: string;
    17→  url?: string;
    18→}
    19→
    20→export interface AuditResult {
    21→  timestamp: Date;
    22→  vulnerabilities: Vulnerability[];
    23→  summary: {
    24→    total: number;
    25→    critical: number;
    26→    high: number;
    27→    moderate: number;
    28→    low: number;
    29→  };
    30→  dependencies: {
    31→    total: number;
    32→    direct: number;
    33→    dev: number;
    34→  };
    35→}
    36→
    37→export interface AuditOptions {
    38→  /** Path to package.json */
    39→  packagePath?: string;
    40→  /** Include dev dependencies */
    41→  includeDev?: boolean;
    42→  /** Severity threshold to fail on */
    43→  failOn?: 'low' | 'moderate' | 'high' | 'critical';
    44→  /** Output format */
    45→  format?: 'json' | 'html' | 'markdown';
    46→  /** Save audit report */
    47→  outputPath?: string;
    48→  /** Use offline cache */
    49→  offline?: boolean;
    50→}
    51→
    52→export class DependencyAuditor {
    53→  private packagePath: string;
    54→  private vulnerabilityDatabase: Map<string, Vulnerability[]> = new Map();
    55→
    56→  constructor(packagePath?: string) {
    57→    this.packagePath = packagePath || process.cwd();
    58→  }
    59→
    60→  /**
    61→   * Run security audit on dependencies
    62→   */
    63→  async audit(options: AuditOptions = {}): Promise<AuditResult> {
    64→    const packageJsonPath = resolve(options.packagePath || this.packagePath, 'package.json');
    65→    
    66→    if (!existsSync(packageJsonPath)) {
    67→      throw new Error(`package.json not found at ${packageJsonPath}`);
    68→    }
    69→
    70→    // Run npm audit
    71→    const auditData = this.runNpmAudit(dirname(packageJsonPath), options);
    72→    
    73→    // Parse vulnerabilities
    74→    const vulnerabilities = this.parseAuditData(auditData);
    75→    
    76→    // Get dependency stats
    77→    const depStats = this.getDependencyStats(packageJsonPath);
    78→    
    79→    // Create result
    80→    const result: AuditResult = {
    81→      timestamp: new Date(),
    82→      vulnerabilities,
    83→      summary: this.summarizeVulnerabilities(vulnerabilities),
    84→      dependencies: depStats
    85→    };
    86→
    87→    // Save report if requested
    88→    if (options.outputPath) {
    89→      this.saveReport(result, options.outputPath, options.format || 'json');
    90→    }
    91→
    92→    // Check failure threshold
    93→    if (options.failOn) {
    94→      this.checkFailureThreshold(result, options.failOn);
    95→    }
    96→
    97→    return result;
    98→  }
    99→
   100→  /**
   101→   * Run npm audit command
   102→   */
   103→  private runNpmAudit(cwd: string, options: AuditOptions): any {
   104→    try {
   105→      const args = ['audit', '--json'];
   106→      
   107→      if (!options.includeDev) {
   108→        args.push('--production');
   109→      }
   110→      
   111→      if (options.offline) {
   112→        args.push('--offline');
   113→      }
   114→
   115→      const output = execSync(`npm ${args.join(' ')}`, {
   116→        cwd,
   117→        encoding: 'utf8',
   118→        stdio: ['pipe', 'pipe', 'ignore'] // Ignore stderr
   119→      });
   120→
   121→      return JSON.parse(output);
   122→    } catch (error: any) {
   123→      // npm audit exits with non-zero when vulnerabilities found
   124→      if (error.stdout) {
   125→        try {
   126→          return JSON.parse(error.stdout);
   127→        } catch {
   128→          throw new Error('Failed to parse npm audit output');
   129→        }
   130→      }
   131→      throw error;
   132→    }
   133→  }
   134→
   135→  /**
   136→   * Parse npm audit data into vulnerabilities
   137→   */
   138→  private parseAuditData(auditData: any): Vulnerability[] {
   139→    const vulnerabilities: Vulnerability[] = [];
   140→
   141→    if (auditData.vulnerabilities) {
   142→      for (const [module, vulnData] of Object.entries(auditData.vulnerabilities)) {
   143→        const vuln = vulnData as any;
   144→        
   145→        vulnerabilities.push({
   146→          id: vuln.via?.[0]?.id || 'unknown',
   147→          title: vuln.via?.[0]?.title || vuln.name || 'Unknown vulnerability',
   148→          severity: vuln.severity as any,
   149→          module,
   150→          version: vuln.range || 'unknown',
   151→          path: vuln.nodes?.join(' > ') || module,
