/**
 * Dependency Auditor for security vulnerability scanning
 */

import { execSync } from 'child_process';
import { readFileSync, writeFileSync, existsSync } from 'fs';
import { resolve, dirname } from 'path';

export interface Vulnerability {
  id: string;
  title: string;
  severity: 'low' | 'moderate' | 'high' | 'critical';
  module: string;
  version: string;
  path: string;
  recommendation: string;
  url?: string;
}

export interface AuditResult {
  timestamp: Date;
  vulnerabilities: Vulnerability[];
  summary: {
    total: number;
    critical: number;
    high: number;
    moderate: number;
    low: number;
  };
  dependencies: {
    total: number;
    direct: number;
    dev: number;
  };
}

export interface AuditOptions {
  /** Path to package.json */
  packagePath?: string;
  /** Include dev dependencies */
  includeDev?: boolean;
  /** Severity threshold to fail on */
  failOn?: 'low' | 'moderate' | 'high' | 'critical';
  /** Output format */
  format?: 'json' | 'html' | 'markdown';
  /** Save audit report */
  outputPath?: string;
  /** Use offline cache */
  offline?: boolean;
}

export class DependencyAuditor {
  private packagePath: string;
  private vulnerabilityDatabase: Map<string, Vulnerability[]> = new Map();

  constructor(packagePath?: string) {
    this.packagePath = packagePath || process.cwd();
  }

  /**
   * Run security audit on dependencies
   */
  async audit(options: AuditOptions = {}): Promise<AuditResult> {
    const packageJsonPath = resolve(options.packagePath || this.packagePath, 'package.json');

    if (!existsSync(packageJsonPath)) {
      throw new Error(`package.json not found at ${packageJsonPath}`);
    }

    // Run npm audit
    const auditData = this.runNpmAudit(dirname(packageJsonPath), options);

    // Parse vulnerabilities
    const vulnerabilities = this.parseAuditData(auditData);

    // Get dependency stats
    const depStats = this.getDependencyStats(packageJsonPath);

    // Create result
    const result: AuditResult = {
      timestamp: new Date(),
      vulnerabilities,
      summary: this.summarizeVulnerabilities(vulnerabilities),
      dependencies: depStats
    };

    // Save report if requested
    if (options.outputPath) {
      this.saveReport(result, options.outputPath, options.format || 'json');
    }

    // Check failure threshold
    if (options.failOn) {
      this.checkFailureThreshold(result, options.failOn);
    }

    return result;
  }

  /**
   * Run npm audit command
   */
  private runNpmAudit(cwd: string, options: AuditOptions): any {
    try {
      const args = ['audit', '--json'];

      if (!options.includeDev) {
        args.push('--production');
      }

      if (options.offline) {
        args.push('--offline');
      }

      const output = execSync(`npm ${args.join(' ')}`, {
        cwd,
        encoding: 'utf8',
        stdio: ['pipe', 'pipe', 'ignore'] // Ignore stderr
      });

      return JSON.parse(output);
    } catch (error: any) {
      // npm audit exits with non-zero when vulnerabilities found
      if (error.stdout) {
        try {
          return JSON.parse(error.stdout);
        } catch {
          throw new Error('Failed to parse npm audit output');
        }
      }
      throw error;
    }
  }

  /**
   * Parse npm audit data into vulnerabilities
   */
  private parseAuditData(auditData: any): Vulnerability[] {
    const vulnerabilities: Vulnerability[] = [];

    if (auditData.vulnerabilities) {
      for (const [module, vulnData] of Object.entries(auditData.vulnerabilities)) {
        const vuln = vulnData as any;

        vulnerabilities.push({
          id: vuln.via?.[0]?.id || 'unknown',
          title: vuln.via?.[0]?.title || vuln.name || 'Unknown vulnerability',
          severity: vuln.severity as any,
          module,
          version: vuln.range || 'unknown',
          path: vuln.nodes?.join(' > ') || module,
          recommendation: vuln.fixAvailable 
            ? `Update to ${vuln.fixAvailable.name}@${vuln.fixAvailable.version}`
            : 'No fix available',
          url: vuln.via?.[0]?.url
        });
      }
    }

    return vulnerabilities;
  }

  /**
   * Get dependency statistics
   */
  private getDependencyStats(packageJsonPath: string): AuditResult['dependencies'] {
    const packageJson = JSON.parse(readFileSync(packageJsonPath, 'utf8'));

    const directDeps = Object.keys(packageJson.dependencies || {}).length;
    const devDeps = Object.keys(packageJson.devDependencies || {}).length;

    // Get total from node_modules (simplified - in reality would count actual modules)
    const total = directDeps + devDeps; // This is simplified

    return {
      total,
      direct: directDeps,
      dev: devDeps
    };
  }

  /**
   * Summarize vulnerabilities by severity
   */
  private summarizeVulnerabilities(vulnerabilities: Vulnerability[]): AuditResult['summary'] {
    const summary = {
      total: vulnerabilities.length,
      critical: 0,
      high: 0,
      moderate: 0,
      low: 0
    };

    vulnerabilities.forEach(vuln => {
      summary[vuln.severity]++;
    });

    return summary;
  }

  /**
   * Check if audit should fail based on threshold
   */
  private checkFailureThreshold(result: AuditResult, threshold: string): void {
    const severityOrder = ['low', 'moderate', 'high', 'critical'];
    const thresholdIndex = severityOrder.indexOf(threshold);

    for (let i = thresholdIndex; i < severityOrder.length; i++) {
      const severity = severityOrder[i] as keyof typeof result.summary;
      if (result.summary[severity] > 0) {
        throw new Error(
          `Security audit failed: Found ${result.summary[severity]} ${severity} severity vulnerabilities`
        );
      }
    }
  }

  /**
   * Save audit report
   */
  private saveReport(result: AuditResult, outputPath: string, format: string): void {
    let content: string;

    switch (format) {
      case 'json':
        content = JSON.stringify(result, null, 2);
        break;
      case 'markdown':
        content = this.generateMarkdownReport(result);
        break;
      case 'html':
        content = this.generateHTMLReport(result);
        break;
      default:
        content = JSON.stringify(result, null, 2);
    }

    writeFileSync(outputPath, content);
  }

  /**
   * Generate markdown report
   */
  private generateMarkdownReport(result: AuditResult): string {
    let report = '# Dependency Security Audit Report\n\n';
    report += `**Generated:** ${result.timestamp.toISOString()}\n\n`;

    report += '## Summary\n\n';
    report += `- Total Vulnerabilities: ${result.summary.total}\n`;
    report += `- Critical: ${result.summary.critical}\n`;
    report += `- High: ${result.summary.high}\n`;
    report += `- Moderate: ${result.summary.moderate}\n`;
    report += `- Low: ${result.summary.low}\n\n`;

    report += '## Dependencies\n\n';
    report += `- Total: ${result.dependencies.total}\n`;
    report += `- Direct: ${result.dependencies.direct}\n`;
    report += `- Dev: ${result.dependencies.dev}\n\n`;

    if (result.vulnerabilities.length > 0) {
      report += '## Vulnerabilities\n\n';

      // Group by severity
      const grouped = result.vulnerabilities.reduce((acc, vuln) => {
        if (!acc[vuln.severity]) acc[vuln.severity] = [];
        acc[vuln.severity].push(vuln);
        return acc;
      }, {} as Record<string, Vulnerability[]>);

      ['critical', 'high', 'moderate', 'low'].forEach(severity => {
        const vulns = grouped[severity];
        if (vulns && vulns.length > 0) {
          report += `### ${severity.toUpperCase()} Severity\n\n`;

          vulns.forEach(vuln => {
            report += `#### ${vuln.title}\n`;
            report += `- **Module:** ${vuln.module}@${vuln.version}\n`;
            report += `- **Path:** ${vuln.path}\n`;
            report += `- **Recommendation:** ${vuln.recommendation}\n`;
            if (vuln.url) {
              report += `- **Details:** ${vuln.url}\n`;
            }
            report += '\n';
          });
        }
      });
    }

    return report;
  }

  /**
   * Generate HTML report
   */
  private generateHTMLReport(result: AuditResult): string {
    const severityColors = {
      critical: '#d32f2f',
      high: '#f44336',
      moderate: '#ff9800',
      low: '#ffc107'
    };

    return `
<!DOCTYPE html>
<html>
<head>
  <title>Dependency Security Audit Report</title>
  <style>
    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      line-height: 1.6;
      color: #333;
      max-width: 1200px;
      margin: 0 auto;
      padding: 20px;
    }
    .header {
      background: #1976d2;
      color: white;
      padding: 20px;
      border-radius: 8px;
      margin-bottom: 20px;
    }
    .summary {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
      gap: 15px;
      margin-bottom: 30px;
    }
    .metric {
      background: #f5f5f5;
      padding: 15px;
      border-radius: 4px;
      text-align: center;
    }
    .metric-value {
      font-size: 36px;
      font-weight: bold;
    }
    .vulnerability {
      background: white;
      border: 1px solid #ddd;
      padding: 15px;
      margin-bottom: 10px;
      border-radius: 4px;
    }
    .severity {
      display: inline-block;
      padding: 2px 8px;
      border-radius: 3px;
      color: white;
      font-weight: bold;
      text-transform: uppercase;
      font-size: 12px;
    }
    .critical { background: ${severityColors.critical}; }
    .high { background: ${severityColors.high}; }
    .moderate { background: ${severityColors.moderate}; }
    .low { background: ${severityColors.low}; }
  </style>
</head>
<body>
  <div class="header">
    <h1>Dependency Security Audit Report</h1>
    <p>Generated: ${result.timestamp.toLocaleString()}</p>
  </div>

  <div class="summary">
    <div class="metric">
      <div class="metric-value">${result.summary.total}</div>
      <div>Total Vulnerabilities</div>
    </div>
    <div class="metric" style="color: ${severityColors.critical}">
      <div class="metric-value">${result.summary.critical}</div>
      <div>Critical</div>
    </div>
    <div class="metric" style="color: ${severityColors.high}">
      <div class="metric-value">${result.summary.high}</div>
      <div>High</div>
    </div>
    <div class="metric" style="color: ${severityColors.moderate}">
      <div class="metric-value">${result.summary.moderate}</div>
      <div>Moderate</div>
    </div>
    <div class="metric" style="color: ${severityColors.low}">
      <div class="metric-value">${result.summary.low}</div>
      <div>Low</div>
    </div>
  </div>

  <h2>Vulnerabilities</h2>
  ${result.vulnerabilities.map(vuln => `
    <div class="vulnerability">
      <span class="severity ${vuln.severity}">${vuln.severity}</span>
      <h3>${vuln.title}</h3>
      <p><strong>Module:</strong> ${vuln.module}@${vuln.version}</p>
      <p><strong>Path:</strong> <code>${vuln.path}</code></p>
      <p><strong>Recommendation:</strong> ${vuln.recommendation}</p>
      ${vuln.url ? `<p><strong>Details:</strong> <a href="${vuln.url}" target="_blank">${vuln.url}</a></p>` : ''}
    </div>
  `).join('')}
</body>
</html>
    `;
  }

  /**
   * Check for known vulnerable patterns in code
   */
  async checkCodePatterns(filePaths: string[]): Promise<string[]> {
    const warnings: string[] = [];
    const dangerousPatterns = [
      { pattern: /eval\s*\(/, message: 'Use of eval() is dangerous' },
      { pattern: /innerHTML\s*=/, message: 'Direct innerHTML assignment can lead to XSS' },
      { pattern: /document\.write/, message: 'document.write() is dangerous' },
      { pattern: /new\s+Function\s*\(/, message: 'Dynamic function creation is risky' },
      { pattern: /\.html\s*\(/, message: 'jQuery html() can lead to XSS' }
    ];

    for (const filePath of filePaths) {
      if (existsSync(filePath)) {
        const content = readFileSync(filePath, 'utf8');

        dangerousPatterns.forEach(({ pattern, message }) => {
          if (pattern.test(content)) {
            warnings.push(`${filePath}: ${message}`);
          }
        });
      }
    }

    return warnings;
  }
}

