     5→export interface RateLimitConfig {
     6→  /** Maximum requests per window */
     7→  maxRequests: number;
     8→  /** Time window in milliseconds */
     9→  windowMs: number;
    10→  /** Skip successful requests from counting */
    11→  skipSuccessfulRequests?: boolean;
    12→  /** Skip failed requests from counting */
    13→  skipFailedRequests?: boolean;
    14→  /** Key generator function */
    15→  keyGenerator?: (context: any) => string;
    16→  /** Handler for rate limit exceeded */
    17→  handler?: (context: any) => void;
    18→}
    19→
    20→export interface PayloadLimitConfig {
    21→  /** Maximum payload size in bytes */
    22→  maxSize: number;
    23→  /** Maximum string length for text fields */
    24→  maxStringLength?: number;
    25→  /** Maximum array length */
    26→  maxArrayLength?: number;
    27→  /** Maximum object depth */
    28→  maxDepth?: number;
    29→  /** Allowed content types */
    30→  allowedContentTypes?: string[];
    31→}
    32→
    33→export interface RateLimitEntry {
    34→  count: number;
    35→  resetTime: number;
    36→  firstRequest: number;
    37→  blocked: boolean;
    38→}
    39→
    40→/**
    41→ * Token bucket algorithm for rate limiting
    42→ */
    43→export class RateLimiter {
    44→  private limits = new Map<string, RateLimitEntry>();
    45→  private config: RateLimitConfig;
    46→  private cleanupInterval: NodeJS.Timeout | null = null;
    47→
    48→  constructor(config: RateLimitConfig) {
    49→    this.config = config;
    50→    
    51→    // Start cleanup interval
    52→    this.cleanupInterval = setInterval(() => {
    53→      this.cleanup();
    54→    }, Math.min(config.windowMs, 60000)); // Cleanup at least every minute
    55→  }
    56→
    57→  /**
    58→   * Check if request should be rate limited
    59→   */
    60→  async checkLimit(context: any = {}): Promise<boolean> {
    61→    const key = this.generateKey(context);
    62→    const now = Date.now();
    63→    
    64→    let entry = this.limits.get(key);
    65→    
    66→    if (!entry || now > entry.resetTime) {
    67→      // Create new entry or reset existing
    68→      entry = {
    69→        count: 1,
    70→        resetTime: now + this.config.windowMs,
    71→        firstRequest: now,
    72→        blocked: false,
    73→      };
    74→      this.limits.set(key, entry);
    75→      return true; // Allow first request
    76→    }
    77→    
