     1→/**
     2→ * Memory Profiler for monitoring and optimizing memory usage
     3→ */
     4→
     5→export interface MemorySnapshot {
     6→  timestamp: Date;
     7→  heapUsed: number;
     8→  heapTotal: number;
     9→  external: number;
    10→  arrayBuffers: number;
    11→  domNodes?: number;
    12→  jsEventListeners?: number;
    13→  detachedNodes?: number;
    14→}
    15→
    16→export interface MemoryMetrics {
    17→  current: MemorySnapshot;
    18→  baseline: MemorySnapshot;
    19→  peak: MemorySnapshot;
    20→  average: MemorySnapshot;
    21→  samples: number;
    22→  duration: number;
    23→  leakSuspected: boolean;
    24→  recommendations: string[];
    25→}
    26→
    27→export interface ProfilerOptions {
    28→  /** Enable automatic profiling */
    29→  enabled: boolean;
    30→  /** Sampling interval in milliseconds */
    31→  samplingInterval?: number;
    32→  /** Memory threshold for warnings (MB) */
    33→  warningThreshold?: number;
    34→  /** Memory threshold for errors (MB) */
    35→  errorThreshold?: number;
    36→  /** Enable heap snapshots */
    37→  enableSnapshots?: boolean;
    38→  /** Enable DOM monitoring */
    39→  enableDOMMonitoring?: boolean;
    40→  /** Maximum samples to keep */
    41→  maxSamples?: number;
    42→}
    43→
    44→/**
    45→ * Memory profiler for experiment runtime monitoring
    46→ */
    47→export class MemoryProfiler {
    48→  private enabled: boolean;
    49→  private options: Required<ProfilerOptions>;
    50→  private samples: MemorySnapshot[] = [];
    51→  private baseline: MemorySnapshot | null = null;
    52→  private peak: MemorySnapshot | null = null;
    53→  private interval: NodeJS.Timeout | null = null;
    54→  private startTime: number = 0;
    55→  private observers: Set<(metrics: MemoryMetrics) => void> = new Set();
    56→
    57→  constructor(options: ProfilerOptions = { enabled: true }) {
    58→    this.enabled = options.enabled;
    59→    this.options = {
    60→      enabled: options.enabled,
    61→      samplingInterval: options.samplingInterval || 1000,
    62→      warningThreshold: options.warningThreshold || 100, // 100MB
    63→      errorThreshold: options.errorThreshold || 500, // 500MB
    64→      enableSnapshots: options.enableSnapshots ?? true,
    65→      enableDOMMonitoring: options.enableDOMMonitoring ?? true,
    66→      maxSamples: options.maxSamples || 1000,
    67→    };
    68→  }
    69→
    70→  /**
    71→   * Start memory profiling
    72→   */
    73→  start(): void {
    74→    if (!this.enabled || this.interval) return;
    75→
    76→    this.startTime = performance.now();
    77→    this.baseline = this.captureSnapshot();
    78→    this.peak = this.baseline;
    79→    this.samples = [this.baseline];
    80→
    81→    this.interval = setInterval(() => {
    82→      this.sample();
    83→    }, this.options.samplingInterval);
    84→
    85→    // Force initial GC if available
    86→    this.requestGarbageCollection();
    87→  }
    88→
    89→  /**
    90→   * Stop memory profiling
    91→   */
    92→  stop(): void {
    93→    if (this.interval) {
    94→      clearInterval(this.interval);
    95→      this.interval = null;
    96→    }
    97→  }
    98→
    99→  /**
   100→   * Take a memory sample
   101→   */
   102→  private sample(): void {
   103→    const snapshot = this.captureSnapshot();
   104→    this.samples.push(snapshot);
   105→
   106→    // Update peak
   107→    if (!this.peak || snapshot.heapUsed > this.peak.heapUsed) {
   108→      this.peak = snapshot;
   109→    }
   110→
   111→    // Trim old samples
   112→    if (this.samples.length > this.options.maxSamples) {
   113→      this.samples.shift();
   114→    }
   115→
   116→    // Check thresholds
   117→    const heapMB = snapshot.heapUsed / (1024 * 1024);
   118→    if (heapMB > this.options.errorThreshold) {
   119→      this.notifyObservers(this.getMetrics());
   120→      console.error(`Memory usage critical: ${heapMB.toFixed(2)}MB`);
   121→    } else if (heapMB > this.options.warningThreshold) {
   122→      console.warn(`Memory usage high: ${heapMB.toFixed(2)}MB`);
   123→    }
   124→
   125→    // Detect potential leaks
   126→    if (this.detectMemoryLeak()) {
   127→      console.warn('Potential memory leak detected');
   128→    }
   129→
   130→    // Notify observers
   131→    this.notifyObservers(this.getMetrics());
   132→  }
   133→
   134→  /**
   135→   * Capture current memory snapshot
   136→   */
   137→  private captureSnapshot(): MemorySnapshot {
   138→    const snapshot: MemorySnapshot = {
   139→      timestamp: new Date(),
   140→      heapUsed: 0,
   141→      heapTotal: 0,
   142→      external: 0,
   143→      arrayBuffers: 0,
   144→    };
   145→
   146→    // Node.js environment
   147→    if (typeof process !== 'undefined' && process.memoryUsage) {
   148→      const usage = process.memoryUsage();
   149→      snapshot.heapUsed = usage.heapUsed;
   150→      snapshot.heapTotal = usage.heapTotal;
   151→      snapshot.external = usage.external;
   152→      snapshot.arrayBuffers = usage.arrayBuffers || 0;
   153→    }
   154→    // Browser environment
   155→    else if (typeof performance !== 'undefined' && 'memory' in performance) {
   156→      const memory = (performance as any).memory;
   157→      if (memory) {
   158→        snapshot.heapUsed = memory.usedJSHeapSize || 0;
   159→        snapshot.heapTotal = memory.totalJSHeapSize || 0;
   160→        snapshot.external = memory.totalJSHeapSize - memory.usedJSHeapSize;
   161→        snapshot.arrayBuffers = 0; // Not available in browser
   162→      }
   163→    }
   164→
   165→    // DOM monitoring (browser only)
   166→    if (this.options.enableDOMMonitoring && typeof document !== 'undefined') {
   167→      snapshot.domNodes = document.getElementsByTagName('*').length;
   168→      
