/**
 * Memory Optimizer for ForgeScript experiments
 * Provides toggles for verification overhead and memory optimization strategies
 */

import { MemoryProfiler } from './MemoryProfiler';
import { ExperimentOptions } from '../experiments/Experiment';

export interface OptimizationOptions {
  /** Enable formal verification (adds 2-3x memory overhead) */
  enableVerification?: boolean;
  /** Enable aggressive garbage collection */
  aggressiveGC?: boolean;
  /** Enable resource pooling for stimuli */
  enablePooling?: boolean;
  /** Enable lazy loading of resources */
  lazyLoading?: boolean;
  /** Enable stimulus streaming for large files */
  enableStreaming?: boolean;
  /** Maximum memory threshold before optimization kicks in (MB) */
  memoryThreshold?: number;
  /** Enable memory profiling */
  enableProfiling?: boolean;
  /** Stimulus cache size limit (MB) */
  cacheLimit?: number;
}

export interface ResourcePool<T> {
  acquire(): T;
  release(resource: T): void;
  clear(): void;
  size(): number;
}

/**
 * Generic resource pool implementation
 */
export class ObjectPool<T> implements ResourcePool<T> {
  private available: T[] = [];
  private inUse = new Set<T>();
  private factory: () => T;
  private reset: (obj: T) => void;
  private maxSize: number;

  constructor(
    factory: () => T,
    reset: (obj: T) => void,
    maxSize = 100
  ) {
    this.factory = factory;
    this.reset = reset;
    this.maxSize = maxSize;
  }

  acquire(): T {
    let resource: T;

    if (this.available.length > 0) {
      resource = this.available.pop()!;
    } else {
      resource = this.factory();
    }

    this.inUse.add(resource);
    return resource;
  }

  release(resource: T): void {
    if (!this.inUse.has(resource)) {
      return;
    }

    this.inUse.delete(resource);
    this.reset(resource);

    if (this.available.length < this.maxSize) {
      this.available.push(resource);
    }
  }

  clear(): void {
    this.available = [];
    this.inUse.clear();
  }

  size(): number {
    return this.available.length + this.inUse.size;
  }
}

/**
 * Memory optimizer for experiments
 */
export class MemoryOptimizer {
  private options: Required<OptimizationOptions>;
  private profiler?: MemoryProfiler;
  private pools = new Map<string, ResourcePool<any>>();
  private cache = new Map<string, { data: any; size: number; lastAccess: number }>();
  private totalCacheSize = 0;
  private gcInterval?: NodeJS.Timeout;

  constructor(options: OptimizationOptions = {}) {
    this.options = {
      enableVerification: true,
      aggressiveGC: false,
      enablePooling: true,
      lazyLoading: true,
      enableStreaming: true,
      memoryThreshold: 200, // 200MB
      enableProfiling: true,
      cacheLimit: 100, // 100MB cache
      ...options
    };

    if (this.options.enableProfiling) {
      this.profiler = new MemoryProfiler({
        enabled: true,
        warningThreshold: this.options.memoryThreshold,
        errorThreshold: this.options.memoryThreshold * 2
      });
    }

    if (this.options.aggressiveGC) {
      this.startAggressiveGC();
    }
  }

  /**
   * Optimize experiment options based on current settings
   */
  optimizeExperimentOptions(options: ExperimentOptions): ExperimentOptions {
    const optimized = { ...options };

    // Disable verification if memory is constrained
    if (!this.options.enableVerification) {
      console.info('Formal verification disabled for memory optimization');
      // In a real implementation, this would disable verification features
    }

    return optimized;
  }

  /**
   * Start memory profiling
   */
  startProfiling(): void {
    if (this.profiler) {
      this.profiler.start();
    }
  }

  /**
   * Stop memory profiling
   */
  stopProfiling(): void {
    if (this.profiler) {
      this.profiler.stop();
    }
  }

  /**
   * Get memory metrics
   */
  getMetrics() {
    return this.profiler?.getMetrics();
  }

  /**
   * Register a resource pool
   */
  registerPool<T>(
    name: string,
    factory: () => T,
    reset: (obj: T) => void,
    maxSize?: number
  ): void {
    const pool = new ObjectPool(factory, reset, maxSize);
    this.pools.set(name, pool);
  }

  /**
   * Get resource from pool
   */
  acquireFromPool<T>(poolName: string): T | null {
    const pool = this.pools.get(poolName);
    return pool ? pool.acquire() : null;
  }

  /**
   * Return resource to pool
   */
  releaseToPool<T>(poolName: string, resource: T): void {
    const pool = this.pools.get(poolName);
    if (pool) {
      pool.release(resource);
    }
  }

  /**
   * Cache a resource
   */
  cache(key: string, data: any, sizeInBytes: number): void {
    if (!this.options.lazyLoading) return;

    // Check cache limit
    if (this.totalCacheSize + sizeInBytes > this.options.cacheLimit * 1024 * 1024) {
      this.evictLRU();
    }

    this.cache.set(key, {
      data,
      size: sizeInBytes,
      lastAccess: Date.now()
    });
    this.totalCacheSize += sizeInBytes;
  }

  /**
   * Get cached resource
   */
  getCached(key: string): any | null {
    const entry = this.cache.get(key);
    if (entry) {
      entry.lastAccess = Date.now();
      return entry.data;
    }
    return null;
  }

  /**
   * Evict least recently used items
   */
  private evictLRU(): void {
    const entries = Array.from(this.cache.entries());
    entries.sort((a, b) => a[1].lastAccess - b[1].lastAccess);

    // Remove oldest entries until we're under 80% of limit
    const targetSize = this.options.cacheLimit * 1024 * 1024 * 0.8;
    while (this.totalCacheSize > targetSize && entries.length > 0) {
      const [key, entry] = entries.shift()!;
      this.cache.delete(key);
      this.totalCacheSize -= entry.size;
    }
  }

  /**
   * Clear all caches and pools
   */
  clearAll(): void {
    // Clear pools
    for (const pool of this.pools.values()) {
      pool.clear();
    }

    // Clear cache
    this.cache.clear();
    this.totalCacheSize = 0;

    // Request GC
    this.requestGC();
  }

  /**
   * Start aggressive garbage collection
   */
  private startAggressiveGC(): void {
    this.gcInterval = setInterval(() => {
      const metrics = this.profiler?.getMetrics();
      if (metrics && metrics.current.heapUsed > this.options.memoryThreshold * 1024 * 1024) {
        this.requestGC();
      }
    }, 5000); // Check every 5 seconds
  }

  /**
   * Request garbage collection
   */
  private requestGC(): void {
    if (typeof global !== 'undefined' && (global as any).gc) {
      (global as any).gc();
    } else if (typeof window !== 'undefined' && (window as any).gc) {
      (window as any).gc();
    }
  }

  /**
   * Create streaming loader for large resources
   */
  createStreamingLoader(url: string, chunkSize = 1024 * 1024): AsyncGenerator<ArrayBuffer> {
    if (!this.options.enableStreaming) {
      throw new Error('Streaming is disabled');
    }

    return this.streamResource(url, chunkSize);
  }

  /**
   * Stream resource in chunks
   */
  private async *streamResource(url: string, chunkSize: number): AsyncGenerator<ArrayBuffer> {
    const response = await fetch(url);
    const reader = response.body?.getReader();

    if (!reader) {
      throw new Error('Failed to create stream reader');
    }

    try {
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        // Process in chunks
        for (let i = 0; i < value.length; i += chunkSize) {
          const chunk = value.slice(i, Math.min(i + chunkSize, value.length));
          yield chunk.buffer;
        }
      }
    } finally {
      reader.releaseLock();
    }
  }

  /**
   * Generate optimization report
   */
  generateReport(): string {
    const metrics = this.profiler?.getMetrics();

    let report = '# Memory Optimization Report\n\n';

    report += '## Configuration\n';
    report += `- Verification: ${this.options.enableVerification ? 'Enabled' : 'Disabled'}\n`;
    report += `- Aggressive GC: ${this.options.aggressiveGC ? 'Enabled' : 'Disabled'}\n`;
    report += `- Resource Pooling: ${this.options.enablePooling ? 'Enabled' : 'Disabled'}\n`;
    report += `- Lazy Loading: ${this.options.lazyLoading ? 'Enabled' : 'Disabled'}\n`;
    report += `- Streaming: ${this.options.enableStreaming ? 'Enabled' : 'Disabled'}\n`;
    report += `- Memory Threshold: ${this.options.memoryThreshold}MB\n`;
    report += `- Cache Limit: ${this.options.cacheLimit}MB\n\n`;

    if (metrics) {
      report += '## Memory Metrics\n';
      report += `- Current Heap: ${(metrics.current.heapUsed / 1024 / 1024).toFixed(2)}MB\n`;
      report += `- Peak Heap: ${(metrics.peak.heapUsed / 1024 / 1024).toFixed(2)}MB\n`;
      report += `- Leak Suspected: ${metrics.leakSuspected ? 'Yes' : 'No'}\n\n`;
    }

    report += '## Resource Pools\n';
    for (const [name, pool] of this.pools.entries()) {
      report += `- ${name}: ${pool.size()} objects\n`;
    }
    report += '\n';

    report += '## Cache Status\n';
    report += `- Entries: ${this.cache.size}\n`;
    report += `- Total Size: ${(this.totalCacheSize / 1024 / 1024).toFixed(2)}MB\n`;
    report += `- Usage: ${((this.totalCacheSize / (this.options.cacheLimit * 1024 * 1024)) * 100).toFixed(1)}%\n`;

    if (metrics && metrics.recommendations.length > 0) {
      report += '\n## Recommendations\n';
      metrics.recommendations.forEach(rec => {
        report += `- ${rec}\n`;
      });
    }

    return report;
  }

  /**
   * Destroy optimizer
   */
  destroy(): void {
    if (this.gcInterval) {
      clearInterval(this.gcInterval);
      this.gcInterval = undefined;
    }

    this.clearAll();
    this.profiler?.reset();
  }
}

/**
 * Memory optimization strategies
 */
export const OptimizationStrategies = {
  /**
   * Low memory mode - disable all non-essential features
   */
  lowMemory: {
    enableVerification: false,
    aggressiveGC: true,
    enablePooling: true,
    lazyLoading: true,
    enableStreaming: true,
    memoryThreshold: 50,
    cacheLimit: 20
  } as OptimizationOptions,

  /**
   * Balanced mode - good performance with reasonable memory usage
   */
  balanced: {
    enableVerification: true,
    aggressiveGC: false,
    enablePooling: true,
    lazyLoading: true,
    enableStreaming: true,
    memoryThreshold: 200,
    cacheLimit: 100
  } as OptimizationOptions,

  /**
   * Performance mode - maximize speed, use more memory
   */
  performance: {
    enableVerification: true,
    aggressiveGC: false,
    enablePooling: false,
    lazyLoading: false,
    enableStreaming: false,
    memoryThreshold: 500,
    cacheLimit: 500
  } as OptimizationOptions,

  /**
   * Development mode - all features enabled for debugging
   */
  development: {
