/**
 * Memory Dashboard for real-time performance monitoring
 */

import { MemoryProfiler } from './MemoryProfiler';
import { PerformanceMonitor } from '../validation/PerformanceMonitor';
import { MemoryOptimizer } from './MemoryOptimizer';

export interface DashboardOptions {
  /** Update interval in milliseconds */
  updateInterval?: number;
  /** Enable visual overlay */
  enableOverlay?: boolean;
  /** Position of overlay */
  overlayPosition?: 'top-left' | 'top-right' | 'bottom-left' | 'bottom-right';
  /** Enable console logging */
  enableLogging?: boolean;
  /** Enable performance alerts */
  enableAlerts?: boolean;
}

export interface DashboardMetrics {
  memory: {
    heapUsed: number;
    heapTotal: number;
    heapPercent: number;
    trend: 'stable' | 'increasing' | 'decreasing';
  };
  performance: {
    fps: number;
    frameTime: number;
    droppedFrames: number;
  };
  optimization: {
    verificationType: boolean;
    pooledResources: number;
    cacheSize: number;
    cacheHitRate: number;
  };
}

/**
 * Real-time memory and performance dashboard
 */
export class MemoryDashboard {
  private profiler: MemoryProfiler;
  private performanceMonitor: PerformanceMonitor;
  private optimizer: MemoryOptimizer;
  private options: Required<DashboardOptions>;
  private overlay?: HTMLDivElement;
  private updateInterval?: NodeJS.Timeout;
  private metrics: DashboardMetrics[] = [];
  private cacheHits = 0;
  private cacheMisses = 0;

  constructor(
    profiler: MemoryProfiler,
    performanceMonitor: PerformanceMonitor,
    optimizer: MemoryOptimizer,
    options: DashboardOptions = {}
  ) {
    this.profiler = profiler;
    this.performanceMonitor = performanceMonitor;
    this.optimizer = optimizer;

    this.options = {
      updateInterval: 1000,
      enableOverlay: true,
      overlayPosition: 'top-right',
      enableLogging: false,
      enableAlerts: true,
      ...options
    };

    if (this.options.enableOverlay && typeof document !== 'undefined') {
      this.createOverlay();
    }

    this.start();
  }

  /**
   * Start dashboard monitoring
   */
  start(): void {
    if (this.updateInterval) return;

    this.profiler.start();
    this.performanceMonitor.start();

    // Subscribe to profiler updates
    this.profiler.subscribe(metrics => {
      if (this.options.enableAlerts && metrics.leakSuspected) {
        this.showAlert('Memory leak suspected!', 'warning');
      }
    });

    // Subscribe to performance warnings
    this.performanceMonitor.on('warning', (warning: any) => {
      if (this.options.enableAlerts) {
        this.showAlert(warning.message, 'error');
      }
    });

    this.updateInterval = setInterval(() => {
      this.update();
    }, this.options.updateInterval);
  }

  /**
   * Stop dashboard monitoring
   */
  stop(): void {
    if (this.updateInterval) {
      clearInterval(this.updateInterval);
      this.updateInterval = undefined;
    }

    this.profiler.stop();
    this.performanceMonitor.stop();

    if (this.overlay) {
      this.overlay.remove();
      this.overlay = undefined;
    }
  }

  /**
   * Update dashboard metrics
   */
  private update(): void {
    const memoryMetrics = this.profiler.getMetrics();
    const perfMetrics = this.performanceMonitor.getLatestMetrics();
    const optimizerReport = this.optimizer.generateReport();

    // Calculate cache hit rate
    const totalCacheRequests = this.cacheHits + this.cacheMisses;
    const cacheHitRate = totalCacheRequests > 0 ? this.cacheHits / totalCacheRequests : 0;

    const metrics: DashboardMetrics = {
      memory: {
        heapUsed: memoryMetrics.current.heapUsed,
        heapTotal: memoryMetrics.current.heapTotal,
        heapPercent: (memoryMetrics.current.heapUsed / memoryMetrics.current.heapTotal) * 100,
        trend: this.calculateTrend(memoryMetrics)
      },
      performance: {
        fps: perfMetrics?.fps || 0,
        frameTime: perfMetrics?.frameTime || 0,
        droppedFrames: perfMetrics?.droppedFrames || 0
      },
      optimization: {
        verificationType: true, // Get from optimizer
        pooledResources: this.countPooledResources(),
        cacheSize: this.getCacheSize(),
        cacheHitRate
      }
    };

    this.metrics.push(metrics);

    // Keep only last 100 metrics
    if (this.metrics.length > 100) {
      this.metrics.shift();
    }

    // Update UI
    if (this.overlay) {
      this.updateOverlay(metrics);
    }

    // Log if enabled
    if (this.options.enableLogging) {
      this.logMetrics(metrics);
    }
  }

  /**
   * Create overlay UI
   */
  private createOverlay(): void {
    this.overlay = document.createElement('div');
    this.overlay.id = 'memory-dashboard';
    this.overlay.style.cssText = `
      position: fixed;
      ${this.options.overlayPosition.includes('top') ? 'top: 10px' : 'bottom: 10px'};
      ${this.options.overlayPosition.includes('left') ? 'left: 10px' : 'right: 10px'};
      background: rgba(0, 0, 0, 0.8);
      color: white;
      padding: 10px;
      font-family: monospace;
      font-size: 12px;
      border-radius: 5px;
      min-width: 250px;
      z-index: 10000;
      pointer-events: none;
    `;

    document.body.appendChild(this.overlay);
  }

  /**
   * Update overlay content
   */
  private updateOverlay(metrics: DashboardMetrics): void {
    if (!this.overlay) return;

    const memoryMB = (metrics.memory.heapUsed / 1024 / 1024).toFixed(1);
    const totalMB = (metrics.memory.heapTotal / 1024 / 1024).toFixed(1);
    const trendIcon = this.getTrendIcon(metrics.memory.trend);

    this.overlay.innerHTML = `
      <div style="font-weight: bold; margin-bottom: 5px;">Performance Monitor</div>
      <div>Memory: ${memoryMB}/${totalMB}MB (${metrics.memory.heapPercent.toFixed(1)}%) ${trendIcon}</div>
      <div>FPS: ${metrics.performance.fps.toFixed(1)} | Frame: ${metrics.performance.frameTime.toFixed(1)}ms</div>
      <div>Dropped: ${metrics.performance.droppedFrames} frames</div>
      <div style="margin-top: 5px; border-top: 1px solid #666; padding-top: 5px;">
        <div>Cache: ${(metrics.optimization.cacheSize / 1024 / 1024).toFixed(1)}MB | Hit: ${(metrics.optimization.cacheHitRate * 100).toFixed(1)}%</div>
        <div>Pooled: ${metrics.optimization.pooledResources} objects</div>
        <div>Verify: ${metrics.optimization.verificationType ? 'ON' : 'OFF'}</div>
      </div>
    `;

    // Color code based on performance
    if (metrics.performance.fps < 30 || metrics.memory.heapPercent > 80) {
      this.overlay.style.borderColor = '#ff4444';
      this.overlay.style.borderWidth = '2px';
      this.overlay.style.borderStyle = 'solid';
    } else if (metrics.performance.fps < 50 || metrics.memory.heapPercent > 60) {
      this.overlay.style.borderColor = '#ffaa44';
      this.overlay.style.borderWidth = '2px';
      this.overlay.style.borderStyle = 'solid';
    } else {
      this.overlay.style.border = 'none';
    }
  }

  /**
   * Calculate memory trend
   */
  private calculateTrend(metrics: any): 'stable' | 'increasing' | 'decreasing' {
    if (this.metrics.length < 5) return 'stable';

    const recent = this.metrics.slice(-5);
    const first = recent[0].memory.heapUsed;
    const last = recent[recent.length - 1].memory.heapUsed;
    const change = (last - first) / first;

    if (change > 0.1) return 'increasing';
    if (change < -0.1) return 'decreasing';
    return 'stable';
  }

  /**
   * Get trend icon
   */
  private getTrendIcon(trend: string): string {
    switch (trend) {
      case 'increasing': return '↑';
      case 'decreasing': return '↓';
      default: return '→';
    }
  }

  /**
   * Count pooled resources
   */
  private countPooledResources(): number {
    // This would query the optimizer's pools
    return 0;
  }

  /**
   * Get cache size
   */
  private getCacheSize(): number {
    // This would query the optimizer's cache
    return 0;
  }

  /**
   * Log metrics to console
   */
  private logMetrics(metrics: DashboardMetrics): void {
    console.log(
      `[Performance] Memory: ${(metrics.memory.heapUsed / 1024 / 1024).toFixed(1)}MB (${metrics.memory.heapPercent.toFixed(1)}%) | ` +
      `FPS: ${metrics.performance.fps.toFixed(1)} | ` +
      `Frame: ${metrics.performance.frameTime.toFixed(1)}ms | ` +
      `Cache Hit: ${(metrics.optimization.cacheHitRate * 100).toFixed(1)}%`
    );
  }

  /**
   * Show alert
   */
  private showAlert(message: string, type: 'warning' | 'error'): void {
    if (!this.overlay) return;

    const alert = document.createElement('div');
    alert.style.cssText = `
      position: fixed;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      background: ${type === 'error' ? '#ff4444' : '#ffaa44'};
      color: white;
      padding: 20px;
      border-radius: 5px;
      font-family: monospace;
      font-size: 14px;
      z-index: 10001;
      pointer-events: none;
    `;
    alert.textContent = message;

    document.body.appendChild(alert);

    setTimeout(() => {
      alert.remove();
    }, 3000);
  }

  /**
   * Export dashboard data
   */
  exportData(): string {
    return JSON.stringify({
      metrics: this.metrics,
      summary: {
        averageFPS: this.calculateAverage('performance.fps'),
        averageMemory: this.calculateAverage('memory.heapUsed'),
        maxMemory: Math.max(...this.metrics.map(m => m.memory.heapUsed)),
        totalDroppedFrames: this.metrics.reduce((sum, m) => sum + m.performance.droppedFrames, 0)
      }
    }, null, 2);
  }

  /**
   * Calculate average for a metric path
   */
  private calculateAverage(path: string): number {
    if (this.metrics.length === 0) return 0;

    const values = this.metrics.map(m => {
      const parts = path.split('.');
      let value: any = m;
      for (const part of parts) {
        value = value[part];
      }
      return value as number;
    });

    return values.reduce((sum, val) => sum + val, 0) / values.length;
  }

  /**
   * Record cache hit
   */
  recordCacheHit(): void {
    this.cacheHits++;
  }

  /**
   * Record cache miss
   */
  recordCacheMiss(): void {
    this.cacheMisses++;
  }
}

