      );

      // Acquire and release
      const obj1 = pool.acquire();
      expect(created).toBe(1);
      expect(obj1.id).toBe(1);

      pool.release(obj1);

      // Should reuse the same object
      const obj2 = pool.acquire();
      expect(created).toBe(1);
      expect(obj2.id).toBe(1);
    });

    it('should limit pool size', () => {
      const pool = new ObjectPool(
        () => ({ data: null }),
        (obj) => { obj.data = null; },
        2
      );

      const objects = [];
      for (let i = 0; i < 5; i++) {
        objects.push(pool.acquire());
      }

      // Release all
      objects.forEach(obj => pool.release(obj));

      // Pool should only keep 2 objects
      expect(pool.size()).toBeLessThanOrEqual(2);
    });
  });

  describe('MemoryOptimizer', () => {
    let optimizer: MemoryOptimizer;

    beforeEach(() => {
      optimizer = new MemoryOptimizer({
        enableProfiling: true,
        memoryThreshold: 100,
        cacheLimit: 50
      });
    });

    afterEach(() => {
      optimizer.destroy();
    });

    it('should register and use resource pools', () => {
      optimizer.registerPool(
        'testPool',
        () => ({ id: Math.random() }),
        (obj) => { obj.id = 0; }
      );

      const obj1 = optimizer.acquireFromPool('testPool');
      expect(obj1).toBeDefined();
      expect(obj1?.id).toBeGreaterThan(0);

      optimizer.releaseToPool('testPool', obj1!);

      const obj2 = optimizer.acquireFromPool('testPool');
      expect(obj2?.id).toBe(0); // Should be reset
    });

    it('should cache resources with LRU eviction', () => {
      // Fill cache
      for (let i = 0; i < 100; i++) {
        optimizer.cache(`key${i}`, `data${i}`, 1024 * 1024); // 1MB each
      }

      // Early items should be evicted
      expect(optimizer.getCached('key0')).toBeNull();

      // Recent items should still be cached
      expect(optimizer.getCached('key99')).toBe('data99');
    });

    it('should create streaming loaders', async () => {
      const chunks: ArrayBuffer[] = [];

      // Mock fetch
      global.fetch = vi.fn().mockResolvedValue({
        body: {
          getReader: () => ({
            read: vi.fn()
              .mockResolvedValueOnce({ done: false, value: new Uint8Array([1, 2, 3]) })
              .mockResolvedValueOnce({ done: false, value: new Uint8Array([4, 5, 6]) })
              .mockResolvedValueOnce({ done: true }),
            releaseLock: vi.fn()
          })
        }
      });

      const loader = optimizer.createStreamingLoader('test.bin', 2);

      for await (const chunk of loader) {
        chunks.push(chunk);
      }

      expect(chunks.length).toBeGreaterThan(0);
    });

    it('should apply optimization strategies', () => {
      const lowMemOptimizer = new MemoryOptimizer(OptimizationStrategies.lowMemory);
      expect(lowMemOptimizer['options'].enableVerification).toBe(false);
      expect(lowMemOptimizer['options'].aggressiveGC).toBe(true);
      expect(lowMemOptimizer['options'].memoryThreshold).toBe(50);
      lowMemOptimizer.destroy();

      const perfOptimizer = new MemoryOptimizer(OptimizationStrategies.performance);
      expect(perfOptimizer['options'].enableVerification).toBe(true);
      expect(perfOptimizer['options'].lazyLoading).toBe(false);
      expect(perfOptimizer['options'].memoryThreshold).toBe(500);
      perfOptimizer.destroy();
    });

    it('should generate optimization report', () => {
      optimizer.registerPool('sprites', () => ({}), () => {});
      optimizer.cache('test', 'data', 1024);

      const report = optimizer.generateReport();

      expect(report).toContain('Memory Optimization Report');
      expect(report).toContain('Configuration');
      expect(report).toContain('Resource Pools');
      expect(report).toContain('Cache Status');
    });
  });

  describe('MemoryDashboard', () => {
    let profiler: MemoryProfiler;
    let monitor: PerformanceMonitor;
    let optimizer: MemoryOptimizer;
    let dashboard: MemoryDashboard;

    beforeEach(() => {
      profiler = new MemoryProfiler({ enabled: true });
      monitor = new PerformanceMonitor();
      optimizer = new MemoryOptimizer();

      // Mock DOM
      document.body.innerHTML = '<div></div>';

      dashboard = new MemoryDashboard(profiler, monitor, optimizer, {
        updateInterval: 100,
        enableOverlay: true,
        enableLogging: false
      });
    });

    afterEach(() => {
      dashboard.stop();
      optimizer.destroy();
    });

    it('should create overlay UI', () => {
      const overlay = document.getElementById('memory-dashboard');
      expect(overlay).toBeDefined();
      expect(overlay?.style.position).toBe('fixed');
    });

    it('should update metrics', async () => {
      vi.advanceTimersByTime(200);

      const overlay = document.getElementById('memory-dashboard');
      expect(overlay?.innerHTML).toContain('Performance Monitor');
      expect(overlay?.innerHTML).toContain('Memory:');
      expect(overlay?.innerHTML).toContain('FPS:');
    });

    it('should track cache performance', () => {
      dashboard.recordCacheHit();
      dashboard.recordCacheHit();
      dashboard.recordCacheMiss();

      vi.advanceTimersByTime(100);

      const overlay = document.getElementById('memory-dashboard');
      expect(overlay?.innerHTML).toContain('Hit: 66.7%');
    });

    it('should export dashboard data', () => {
      vi.advanceTimersByTime(500);

      const data = dashboard.exportData();
      const parsed = JSON.parse(data);

      expect(parsed.metrics).toBeInstanceOf(Array);
      expect(parsed.summary).toBeDefined();
      expect(parsed.summary.averageFPS).toBeDefined();
      expect(parsed.summary.averageMemory).toBeDefined();
    });
  });

  describe('Integration Test', () => {
    it('should optimize memory during experiment', () => {
      const optimizer = new MemoryOptimizer(OptimizationStrategies.balanced);

      // Register stimulus pool
      optimizer.registerPool(
        'stimuli',
        () => ({ type: 'text', content: '', active: false }),
        (stim) => {
          stim.content = '';
          stim.active = false;
        }
      );

      // Simulate experiment with pooled stimuli
      const activeStimuli: any[] = [];

      // Present stimuli
      for (let i = 0; i < 10; i++) {
        const stim = optimizer.acquireFromPool('stimuli');
        if (stim) {
          stim.content = `Stimulus ${i}`;
          stim.active = true;
          activeStimuli.push(stim);
        }
      }

      // Clean up old stimuli
      while (activeStimuli.length > 3) {
        const old = activeStimuli.shift();
        optimizer.releaseToPool('stimuli', old);
      }

      // Cache frequently used resources
      optimizer.cache('instructions', 'Welcome to the experiment', 1024);
      optimizer.cache('fixation', '+', 10);

      // Verify caching works
      expect(optimizer.getCached('instructions')).toBe('Welcome to the experiment');
      expect(optimizer.getCached('fixation')).toBe('+');

      // Generate final report
      const report = optimizer.generateReport();
      expect(report).toContain('stimuli: ');
      expect(report).toContain('Cache Status');

      optimizer.destroy();
    });
  });
});

