import { writable, derived } from 'svelte/store';
import type { AppSettings, Project } from '$lib/types';

// Default settings
const defaultSettings: AppSettings = {
	theme: 'light',
	autoSave: true,
	autoSaveInterval: 30000, // 30 seconds
	showPerformanceOverlay: false,
	accessibility: {
		reduceMotion: false,
		highContrast: false,
		fontSize: 'medium',
	},
};

// Load settings from localStorage if available
function loadSettings(): AppSettings {
	if (typeof window === 'undefined') return defaultSettings;

	const stored = localStorage.getItem('psyforge-settings');
	if (stored) {
		try {
			return { ...defaultSettings, ...JSON.parse(stored) };
		} catch {
			return defaultSettings;
		}
	}
	return defaultSettings;
}

// App settings store
export const settings = writable<AppSettings>(loadSettings());

// Persist settings to localStorage
settings.subscribe((value) => {
	if (typeof window !== 'undefined') {
		localStorage.setItem('psyforge-settings', JSON.stringify(value));
	}
});

// Current project store
export const currentProject = writable<Project | null>(null);

// Loading state
export const isLoading = writable(false);

// Error state
export const error = writable<string | null>(null);

// Derived stores
export const isDarkMode = derived(
	settings,
	($settings) => $settings.theme === 'dark'
);

export const isHighContrast = derived(
	settings,
	($settings) => $settings.theme === 'high-contrast' || $settings.accessibility.highContrast
);

// Utility functions
export function setTheme(theme: AppSettings['theme']) {
	settings.update((s) => ({ ...s, theme }));
}

export function toggleDarkMode() {
	settings.update((s) => ({
		...s,
		theme: s.theme === 'dark' ? 'light' : 'dark',
	}));
}

export function setError(message: string | null) {
	error.set(message);
	if (message) {
		// Auto-clear error after 5 seconds
		setTimeout(() => {
			error.update((e) => (e === message ? null : e));
		}, 5000);
	}
}

